# Production hybrid search at scale (simplified)
from elasticsearch import Elasticsearch
from sentence_transformers import CrossEncoder
import numpy as np

class HybridSearchBatsman:
    def __init__(self, bm25_weight=0.4, dense_weight=0.6):
        self.es = Elasticsearch(['localhost:9200'])
        self.reranker = CrossEncoder('cross-encoder/mmarco-mMiniLMv2-L12-H384')
        self.bm25_weight = bm25_weight
        self.dense_weight = dense_weight

    def search_cricket_stats(self, query_over, top_k=10):
        # Stage 1: Parallel BM25 and dense retrieval
        bm25_hits = self.es.search(
            index='cricket_stats',
            body={
                'query': {'multi_match': {
                    'query': query_over,
                    'fields': ['player_name', 'match_type', 'performance']
                }},
                'size': top_k * 2
            }
        )['hits']['hits']

        dense_hits = self.es.search(
            index='cricket_stats',
            body={
                'query': {'knn': {
                    'embedding': {
                        'vector': self.encode(query_over),
                        'k': top_k * 2
                    }
                }},
                'size': top_k * 2
            }
        )['hits']['hits']

        # Stage 2: Normalize and fuse scores
        bm25_scores = {hit['_id']: hit['_score'] for hit in bm25_hits}
        dense_scores = {hit['_id']: hit['_score'] for hit in dense_hits}

        bm25_max = max(bm25_scores.values()) if bm25_scores else 1
        dense_max = max(dense_scores.values()) if dense_scores else 1

        fused = {}
        for doc_id in set(list(bm25_scores.keys()) + list(dense_scores.keys())):
            norm_bm25 = (bm25_scores.get(doc_id, 0) / bm25_max)
            norm_dense = (dense_scores.get(doc_id, 0) / dense_max)
            fused[doc_id] = (self.bm25_weight * norm_bm25 + 
                           self.dense_weight * norm_dense)

        # Stage 3: Re-rank top candidates with cross-encoder
        candidates = sorted(fused.items(), key=lambda x: x[1], reverse=True)[:top_k]
        docs = [self.es.get(index='cricket_stats', id=doc_id)['_source'] 
                for doc_id, _ in candidates]

        pairs = [[query_over, doc.get('content', '')] for doc in docs]
        rerank_scores = self.reranker.predict(pairs)

        final_results = sorted(
            zip(docs, rerank_scores),
            key=lambda x: x[1],
            reverse=True
        )[:top_k]

        return final_results

    def encode(self, text):
        # Placeholder: use actual embedding model
        return np.random.rand(384)

# Usage
batsman = HybridSearchBatsman(bm25_weight=0.35, dense_weight=0.65)
results = batsman.search_cricket_stats('Virat Kohli Test century performances')
